#include <bits/stdc++.h>
using namespace std;vector<int>p;
int f(int x){return p[x]==x?x:p[x]=f(p[x]);}
int main(){int v,e;scanf("%d %d",&v,&e);vector<array<long long,3>>ed(e);for(auto&x:ed)scanf("%lld %lld %lld",&x[1],&x[2],&x[0]);sort(ed.begin(),ed.end());p.resize(v+1);for(int i=1;i<=v;i++)p[i]=i;long long ans=0;for(auto&x:ed){int a=f(x[1]),b=f(x[2]);if(a!=b){p[a]=b;ans+=x[0];}}printf("%lld\n",ans);}
